import { register, unregister } from '@tauri-apps/plugin-global-shortcut';

export function useKeyboardShortcuts() {
  useEffect(() => {
    const shortcuts = [
      { key: 'CommandOrControl+T', action: () => createNewTab() },
      { key: 'CommandOrControl+W', action: () => closeCurrentTab() },
      { key: 'CommandOrControl+Shift+[', action: () => prevTab() },
      { key: 'CommandOrControl+Shift+]', action: () => nextTab() },
      { key: 'CommandOrControl+,', action: () => openSettings() },
      { key: 'CommandOrControl+K', action: () => openCommandPalette() },
    ];

    shortcuts.forEach(s => register(s.key, s.action));
    return () => shortcuts.forEach(s => unregister(s.key));
  }, []);
}
