import { listen } from '@tauri-apps/api/event';

export function useWindowFocus() {
  const [isFocused, setIsFocused] = useState(true);

  useEffect(() => {
    const unlisten = listen<boolean>('window-focus', (e) => {
      setIsFocused(e.payload);
