}

/* Disable image/element dragging */
img, svg, [draggable="false"] {
  -webkit-user-drag: none;
  user-drag: none;
}

/* Prevent overscroll bounce */
html, body {
  overscroll-behavior: none;
}

/* Titlebar drag region */
.titlebar-drag {
