### Phase 4: Custom Context Menus (Notion-style, using PatternFly)

**Approach:** Use PatternFly's `Menu` + `Popper` components (already installed!) instead of native Tauri menus. This gives us full control over styling and matches Notion/Linear UX.

**New file: `src/components/ContextMenu.tsx`**
```typescript
import { Menu, MenuList, MenuItem, MenuGroup, Divider, Popper } from '@patternfly/react-core';
import { useEffect, useRef, useState } from 'react';

interface ContextMenuItem {
  id: string;
  label: string;
  shortcut?: string;
  icon?: React.ReactNode;
  danger?: boolean;
  disabled?: boolean;
  onClick: () => void;
}

interface ContextMenuProps {
  items: ContextMenuItem[];
  children: React.ReactNode;
}

export function ContextMenu({ items, children }: ContextMenuProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const menuRef = useRef<HTMLDivElement>(null);

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    setPosition({ x: e.clientX, y: e.clientY });
    setIsOpen(true);
  };

  // Close on click outside or Escape
  useEffect(() => {
    const handleClickOutside = () => setIsOpen(false);
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setIsOpen(false);
    };

    if (isOpen) {
      document.addEventListener('click', handleClickOutside);
      document.addEventListener('keydown', handleEscape);
    }
    return () => {
      document.removeEventListener('click', handleClickOutside);
      document.removeEventListener('keydown', handleEscape);
    };
  }, [isOpen]);

  return (
    <>
      <div onContextMenu={handleContextMenu}>{children}</div>
      {isOpen && (
        <div
          ref={menuRef}
          style={{
            position: 'fixed',
            left: position.x,
            top: position.y,
            zIndex: 9999
          }}
        >
          <Menu>
            <MenuList>
              {items.map(item => (
                <MenuItem
                  key={item.id}
                  isDanger={item.danger}
                  isDisabled={item.disabled}
                  onClick={() => { item.onClick(); setIsOpen(false); }}
                >
                  {item.icon}
                  {item.label}
                  {item.shortcut && <span className="context-menu-shortcut">{item.shortcut}</span>}
                </MenuItem>
              ))}
            </MenuList>
          </Menu>
        </div>
      )}
    </>
  );
}
```

**CSS for shortcuts display:**
```css
.context-menu-shortcut {
  margin-left: auto;
  padding-left: 24px;
  opacity: 0.6;
  font-size: 12px;
}
```

**Usage example:**
